const triggerItems = $('Gmail Trigger').all();

return $input.all().map((item, index) => {
  let json;
  try {
    const text = item.json.output;
    const cleaned = text.replace(/```json\n?|```/g, '').trim();
    json = JSON.parse(cleaned);
  } catch (error) {
    // Vang kapotte LLM-output op zodat 1 slechte mail niet de hele batch stuk maakt
    json = {
      category: 'overig',
      confidence: 0,
      summary: 'Kon AI Agent 1 output niet parsen: ' + error.message,
      needs_human: true,
      create_salesforce_case: false,
      parse_error: true,
      raw_output: item.json.output
    };
  }

  const templateCategories = ['nieuwe_gift', 'stop_gift', 'verlaging_gift', 'verhoging_gift'];
  json.use_template = templateCategories.includes(json.category);

  // Index-matching i.p.v. pairedItem — werkt betrouwbaar als elke node 1-op-1 evenveel items teruggeeft
  const trigger = triggerItems[index]?.json;
  json.gmail_id = trigger?.id;
  json.gmail_threadId = trigger?.threadId;
  json.gmail_subject = trigger?.headers?.subject;
  json.gmail_from = trigger?.headers?.from;
  json.gmail_to = trigger?.headers?.to;
  json.gmail_date = trigger?.headers?.date;
  json.gmail_text = trigger?.text;
  json.gmail_snippet = trigger?.snippet;
  json.gmail_labelIds = trigger?.labelIds;

  return { json };
});

const contact = $input.item.json; // Salesforce contact van "Get many contacts"
const emailData = $('Code in JavaScript').item.json; // categorie, summary, etc.

// Map categorie naar Salesforce veld (voor direct debit wijzigingen)
const fieldMap = {
  verhoging_gift: 'Direct_Debit_Amount__c',
  verlaging_gift: 'Direct_Debit_Amount__c',
  nieuwe_gift: 'Direct_Debit_Amount__c',
  stop_gift: 'Donor_Active__c',
};

// Map categorie naar Salesforce Case Reason picklist
const caseReasonMap = {
  nieuwe_gift: 'New direct debit mandate.',
  stop_gift: 'Stop the existing direct debit mandate.',
  verlaging_gift: 'Decrease existing direct debit mandate.',
  verhoging_gift: 'Increase existing direct debit mandate.',
  aanmelding_afmelding: 'Subscription Opt In/Out',
  inkomende_informatie: 'Incoming Information',
  hr_gerelateerd: 'HR Related',
  overig: '--None--',
};

const field_to_update = fieldMap[emailData.category] || '';
const case_reason = caseReasonMap[emailData.category] || '--None--';

// Probeer een bedrag uit de summary te halen (bij gift wijzigingen)
const summaryText = emailData.summary;
const amountMatch = summaryText.match(/€?\s?(\d+)/g);

let new_value = '';

if (emailData.category === 'stop_gift') {
  new_value = false; // donateur wordt inactief
} else if (['verhoging_gift', 'verlaging_gift', 'nieuwe_gift'].includes(emailData.category) && amountMatch) {
  new_value = amountMatch[amountMatch.length - 1].replace(/[^\d]/g, '');
}

return {
  json: {
    needs_human: emailData.needs_human,
    category: emailData.category,
    case_reason,
    account_id: contact.Id || '',
    field_to_update,
    new_value,
    reason: field_to_update
      ? `Update ${field_to_update} naar ${new_value}`
      : 'Geen actie nodig'
  }
};

